const coupons = {
  "CODE1": {
    "discount": 20,
    "expiryDate": new Date("Jan 31, 2023"),
    "used": false
  },
  "CODE2": {
    "discount": 15,
    "expiryDate": new Date("Feb 28, 2023"),
    "used": false
  }
};

function redeemCoupon(couponCode) {
  const coupon = coupons[couponCode];
  if (!coupon || coupon.expiryDate < Date.now()) {
    return null;
  }
  if (coupon.used) {
    return null;
  }
  coupon.used = true;
  return coupon.discount;
}